const FEMIJE_SUBCATEGORY_SLUG_RE = /^femije-(grp|type|leaf)-/;

export function getFemijeSubcategoryDescription(
  slug: string | null | undefined,
  locale: MarketCode,
): string | null {
  if (!slug || !FEMIJE_SUBCATEGORY_SLUG_RE.test(slug)) return null;
  const row = FEMIJE_SUBCATEGORY_DESCRIPTION_BY_SLUG[slug];
  if (!row) return null;
  if (locale === "mk") return row.mk;
  if (locale === "mne") return row.mne;
  return row.sq;
}
